import pyotp
import qrcode
import time

class TOTPAuthenticator:
    def __init__(self):
        self.secrets = {}

    def generate_secret(self, user_id):
        secret = pyotp.random_base32()
        self.secrets[user_id] = secret
        return secret

    def create_qr_code(self, user_id):
        secret = self.secrets[user_id]
        totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(name=user_id, issuer_name="MyApp")
        img = qrcode.make(totp_uri)
        img.save(f"{user_id}_qr.png")

    def validate_totp(self, user_id, token):
        secret = self.secrets.get(user_id)
        if secret:
            totp = pyotp.TOTP(secret)
            return totp.verify(token)
        return False

# Usage example
authenticator = TOTPAuthenticator()
user_id = "user@example.com"
secret = authenticator.generate_secret(user_id)
authenticator.create_qr_code(user_id)

# Simulate user entering a TOTP code
time.sleep(5)  # Wait for a new TOTP to be generated
token = pyotp.TOTP(secret).now()  # Get the current TOTP
is_valid = authenticator.validate_totp(user_id, token)
